# Module for shapes: interfaces, abstract classes, and concrete implementations
from structures import Point

# Interface for shapes
interface IShape:
    def area(self) -> float: ...
    def perimeter(self) -> float: ...

# Interface for drawable objects
interface IDrawable:
    def draw(self) -> str: ...

# Abstract base class for shapes
@abstract
class BaseShape:
    position: Point

    def __init__(self, pos: Point):
        self.position = pos

# Concrete rectangle implementation
class Rectangle(BaseShape, IShape, IDrawable):
    width: float
    height: float

    def __init__(self, pos: Point, w: float, h: float):
        super().__init__(pos)
        self.width = w
        self.height = h

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def draw(self) -> str:
        return "Rectangle"

# Concrete circle implementation
class Circle(BaseShape, IShape, IDrawable):
    radius: float

    def __init__(self, pos: Point, r: float):
        super().__init__(pos)
        self.radius = r

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def draw(self) -> str:
        return "Circle"

