# Module for shape processing utilities
from shapes import IShape, IDrawable

class ShapeProcessor:
    @static
    def get_area(shape: IShape) -> float:
        return shape.area()

    @static
    def get_drawable_description(d: IDrawable) -> str:
        return d.draw()
